import { IMessageComposer } from '@nitrots/nitro-renderer';

export class ArenaRequestLeaderboardComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor()
{
// no payload needed (top 10, server decides)
this._data = [];
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}